const items = $input.all();
const output = [];

for (const item of items) {
  let data = item.json;

  // Si n8n envuelve el array en "body" (común con webhooks)
  if (data.body !== undefined) {
    data = data.body;
  }

  if (Array.isArray(data)) {
    if (data.length === 0) {
      output.push({ json: { valid: false, error: "El payload es una lista vacía" } });
      continue;
    }
    data = data[0];
  }

  const errors = [];
  const requiredFields = ["donante", "cant-items", "cant-types", "date"];

  for (const field of requiredFields) {
    if (data[field] === undefined || data[field] === null) {
      errors.push(`Falta el campo '${field}'`);
    }
  }

  if (errors.length === 0) {
    if (typeof data["donante"] !== "number" || !Number.isInteger(data["donante"])) {
      errors.push(`'donante' debe ser un entero (recibido: ${typeof data["donante"]})`);
    }

    if (typeof data["cant-items"] !== "number" || !Number.isInteger(data["cant-items"]) || data["cant-items"] < 0) {
      errors.push(`'cant-items' debe ser un entero >= 0 (recibido: ${typeof data["cant-items"]})`);
    }

    if (typeof data["cant-types"] !== "number" || !Number.isInteger(data["cant-types"]) || data["cant-types"] < 0) {
      errors.push(`'cant-types' debe ser un entero >= 0 (recibido: ${typeof data["cant-types"]})`);
    }

    if (typeof data["date"] !== "string" || !/^\d{4}-\d{2}-\d{2}$/.test(data["date"])) {
      errors.push(`'date' debe ser un string con formato YYYY-MM-DD (recibido: ${typeof data["date"]}, valor: ${JSON.stringify(data["date"])})`);
    }

    // Validar que no haya campos extra inesperados
    const allowedFields = ["donante", "cant-items", "cant-types", "date"];
    const extraFields = Object.keys(data).filter(k => !allowedFields.includes(k));
    if (extraFields.length > 0) {
      errors.push(`Campos no permitidos: ${extraFields.join(", ")}`);
    }
  }

  if (errors.length > 0) {
    output.push({ json: { valid: false, error: errors.join("; "), data } });
  } else {
    output.push({ json: { valid: true, data } });
  }
}

return output;

const items = $input.all();
const output = [];

for (const item of items) {
  let data = item.json;

  // Si n8n envuelve el payload en "body" (común con webhooks)
  if (data.body !== undefined) {
    data = data.body;
  }

  const errors = [];
  const requiredFields = ["donantes", "date", "beneficiario"];

  for (const field of requiredFields) {
    if (data[field] === undefined || data[field] === null) {
      errors.push(`Falta el campo '${field}'`);
    }
  }

  if (errors.length === 0) {
    // Validar "donantes": array de enteros, longitud >= 1
    if (!Array.isArray(data["donantes"])) {
      errors.push(`'donantes' debe ser un array (recibido: ${typeof data["donantes"]})`);
    } else if (data["donantes"].length === 0) {
      errors.push("'donantes' no puede ser un array vacío");
    } else {
      const invalidDonantes = data["donantes"].filter(
        d => typeof d !== "number" || !Number.isInteger(d)
      );
      if (invalidDonantes.length > 0) {
        errors.push(`'donantes' debe contener solo enteros (valores inválidos: ${JSON.stringify(invalidDonantes)})`);
      }
    }

    // Validar "date"
    if (typeof data["date"] !== "string" || !/^\d{4}-\d{2}-\d{2}$/.test(data["date"])) {
      errors.push(`'date' debe ser un string con formato YYYY-MM-DD (recibido: ${typeof data["date"]}, valor: ${JSON.stringify(data["date"])})`);
    }

    // Validar "beneficiario"
    if (typeof data["beneficiario"] !== "string" || data["beneficiario"].trim().length === 0) {
      errors.push(`'beneficiario' debe ser un string no vacío (recibido: ${typeof data["beneficiario"]})`);
    }

    // Validar que no haya campos extra inesperados
    const allowedFields = ["donantes", "date", "beneficiario"];
    const extraFields = Object.keys(data).filter(k => !allowedFields.includes(k));
    if (extraFields.length > 0) {
      errors.push(`Campos no permitidos: ${extraFields.join(", ")}`);
    }
  }

  if (errors.length > 0) {
    output.push({ json: { valid: false, error: errors.join("; "), data } });
  } else {
    output.push({ json: { valid: true, data } });
  }
}

return output;
